/**
 * Regression tests for multi-page scanned financial documents.
 *
 * Covers:
 * 1. Page order detection and reordering (upload in reverse order)
 * 2. Chunk marker removal ("Страница X/Y" generated by translator)
 * 3. Financial block classification (line items vs totals vs tax summary)
 * 4. Wide table rendering: landscape section, column widths, no word-split
 * 5. Summary blocks are separate (not inside 8-column item grid)
 * 6. Required values preserved in DOCX XML
 * 7. Legal entity names not converted to ООО/ТОО
 * 8. No document AST calls
 *
 * The specific document used for fixtures is a sanitised 2-page receipt-style
 * financial document. Production logic must NOT depend on Thai language,
 * specific brand names, or specific numeric values.
 */

// Mock env before any module that imports it
jest.mock('../env', () => ({
  env: {
    APP_ENV: 'staging',
    NEXT_PUBLIC_SUPABASE_URL: 'https://test.supabase.co',
    SUPABASE_SERVICE_ROLE_KEY: 'test-key',
    R2_ACCOUNT_ID: 'r2', R2_ACCESS_KEY_ID: 'k', R2_SECRET_ACCESS_KEY: 's', R2_BUCKET_NAME: 'b',
    ANTHROPIC_API_KEY: 'test', MISTRAL_API_KEY: 'test',
    RESEND_API_KEY: undefined, SITE_URL: 'https://test.example.com',
    EMAILS_ENABLED: false, EMAIL_REDIRECT_ALL_TO: undefined,
    PAYMENTS_MODE: 'test', OFFICIAL_WORKFLOW_ENABLED: true,
    POLL_INTERVAL_MS: 10000, WORKER_CONCURRENCY: 1,
  },
}));

import { execSync } from 'child_process';
import fs from 'fs';
import os from 'os';
import path from 'path';
import { renderToDocx, LANDSCAPE_WIDTH_DXA } from '../docx-renderer';
import { reorderPagesByEvidence, detectPageEvidence } from '../page-order';
import { classifyFinancialBlock, computeLineItemColumnWidths } from '../financial-blocks';
import { stripInternalChunkMarkersForTest } from '../translator';

// ── Helpers ───────────────────────────────────────────────────────────────────

async function getDocxXml(buf: Buffer): Promise<string> {
  const tmp = path.join(os.tmpdir(), `wpo-fin-${Date.now()}.docx`);
  try {
    fs.writeFileSync(tmp, buf);
    return execSync(`unzip -p "${tmp}" "word/document.xml"`).toString();
  } finally {
    try { fs.unlinkSync(tmp); } catch { /* ignore */ }
  }
}

function extractPlainText(xml: string): string {
  return xml.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ');
}

const RENDER_META = {
  sourceLang: 'th',
  targetLang: 'ru',
  translatedAt: '2026-06-18',
  filename: 'receipt_test.jpg',
  serviceLevel: 'official_with_translator_signature_and_provider_stamp' as const,
  outputMode: 'translator_review_draft' as const,
  documentType: 'other',
};

// ── §1: Page order detection ──────────────────────────────────────────────────

describe('page order detection', () => {
  it('detects English page marker "Page 1 of 2"', () => {
    const ev = detectPageEvidence('Some content\nPage 1 of 2\nMore content', 0);
    expect(ev.detectedPageNumber).toBe(1);
    expect(ev.detectedTotalPages).toBe(2);
    expect(ev.confidence).toBeGreaterThan(0.8);
  });

  it('detects Thai page marker "หน้า 1 จาก 2"', () => {
    const ev = detectPageEvidence('เนื้อหา\nหน้า 2 จาก 2\n', 0);
    expect(ev.detectedPageNumber).toBe(2);
    expect(ev.detectedTotalPages).toBe(2);
  });

  it('detects Russian page marker "Страница 2 из 2"', () => {
    const ev = detectPageEvidence('Содержание\nСтраница 2 из 2', 0);
    expect(ev.detectedPageNumber).toBe(2);
    expect(ev.detectedTotalPages).toBe(2);
  });

  it('reorders pages when uploaded in reverse order', () => {
    // Simulate: uploaded page 2 first, then page 1
    const page2 = 'Invoice header\nPage 2 of 2\nItem table here';
    const page1 = 'Company header\nPage 1 of 2\nDate: 2026-01-15';

    const result = reorderPagesByEvidence([page2, page1]);
    expect(result.reordered).toBe(true);
    // After reorder: first markdown should be page1 content
    expect(result.reorderedMarkdowns[0]).toContain('Company header');
    expect(result.reorderedMarkdowns[1]).toContain('Invoice header');
  });

  it('does not reorder when pages are already in order', () => {
    const page1 = 'Content\n1 of 2';
    const page2 = 'Content\n2 of 2';
    const result = reorderPagesByEvidence([page1, page2]);
    expect(result.reordered).toBe(false);
    expect(result.reorderedMarkdowns[0]).toBe(page1);
  });

  it('does not reorder when page numbers are ambiguous (duplicate)', () => {
    const p1 = 'Content\nPage 1 of 2';
    const p2 = 'Content\nPage 1 of 2'; // duplicate
    const result = reorderPagesByEvidence([p1, p2]);
    expect(result.reordered).toBe(false);
    expect(result.warning).toBe('PAGE_ORDER_DUPLICATE_NUMBERS');
  });

  it('does not reorder when detection partial', () => {
    const p1 = 'Content\nPage 1 of 2';
    const p2 = 'No page number here';
    const result = reorderPagesByEvidence([p1, p2]);
    expect(result.reordered).toBe(false);
    expect(result.warning).toBe('PAGE_ORDER_DETECTION_PARTIAL');
  });

  it('single page: no reorder', () => {
    const result = reorderPagesByEvidence(['Single page content']);
    expect(result.reordered).toBe(false);
    expect(result.reorderedMarkdowns).toHaveLength(1);
  });
});

// ── §2: Chunk marker removal ──────────────────────────────────────────────────

describe('chunk marker removal', () => {
  it('strips standalone "Страница 1/4" from translation output', () => {
    const input = 'Line 1\nСтраница 1/4\nLine 3';
    expect(stripInternalChunkMarkersForTest(input)).not.toContain('Страница 1/4');
    expect(stripInternalChunkMarkersForTest(input)).toContain('Line 1');
    expect(stripInternalChunkMarkersForTest(input)).toContain('Line 3');
  });

  it('strips standalone "Page 3/5" from translation output', () => {
    const input = 'Content before\nPage 3/5\nContent after';
    const out = stripInternalChunkMarkersForTest(input);
    expect(out).not.toContain('Page 3/5');
    expect(out).toContain('Content before');
    expect(out).toContain('Content after');
  });

  it('strips "Chunk 2/4" marker', () => {
    const input = 'Before\nChunk 2/4\nAfter';
    expect(stripInternalChunkMarkersForTest(input)).not.toContain('Chunk 2/4');
  });

  it('preserves "Page 1 of 2" (source content, not chunk marker)', () => {
    const input = 'Footer text: Page 1 of 2';
    // "Page 1 of 2" uses "of", not "/" — not a chunk marker
    expect(stripInternalChunkMarkersForTest(input)).toContain('Page 1 of 2');
  });

  it('preserves "Страница 1 из 2" (source content)', () => {
    const input = 'Страница 1 из 2';
    expect(stripInternalChunkMarkersForTest(input)).toContain('Страница 1 из 2');
  });

  it('does not strip partial matches inside prose', () => {
    const input = 'The document has 3/4 of the required pages.';
    // "3/4" in middle of sentence — not a standalone marker
    expect(stripInternalChunkMarkersForTest(input)).toContain('3/4');
  });
});

// ── §3: Financial block classification ───────────────────────────────────────

describe('financial block classification', () => {
  it('classifies 8-column table as line_items (wide)', () => {
    const headers = ['#', 'Article', 'Description', 'Qty', 'Unit', 'Price', 'VAT', 'Total'];
    const rows = Array.from({ length: 10 }, (_, i) => [
      String(i + 1), `ART-${i}`, `Product description ${i}`, '5', 'pcs', '100.00', '7%', '500.00',
    ]);
    const result = classifyFinancialBlock(headers, rows);
    expect(result.kind).toBe('line_items');
    expect(result.isWide).toBe(true);
    expect(result.columnCount).toBe(8);
  });

  it('classifies 7-column table as line_items (wide)', () => {
    const headers = ['#', 'Description', 'Qty', 'Unit', 'Price', 'VAT', 'Total'];
    const rows = Array.from({ length: 5 }, (_, i) => [
      String(i + 1), `Item ${i}`, '10', 'pcs', '50.00', '7%', '500.00',
    ]);
    const result = classifyFinancialBlock(headers, rows);
    expect(result.isWide).toBe(true);
  });

  it('classifies VAT table as tax_summary', () => {
    const headers = ['VAT code', 'Tax base', 'VAT amount', 'Gross'];
    const rows = [['7%', '2,716.70', '190.17', '2,906.87'], ['Exempt', '192.17', '0.00', '192.17']];
    const result = classifyFinancialBlock(headers, rows);
    expect(result.kind).toBe('tax_summary');
    expect(result.isWide).toBe(false);
  });

  it('classifies narrow label+amount table as totals', () => {
    const headers = ['Item', 'Amount'];
    const rows = [
      ['Total', '2,955.25'],
      ['Discount', '0.00'],
      ['Net amount', '2,955.25'],
    ];
    const result = classifyFinancialBlock(headers, rows);
    expect(result.kind).toBe('totals');
    expect(result.isWide).toBe(false);
  });

  it('classifies payment breakdown table', () => {
    const headers = ['POD', 'Coupon', 'Voucher', 'Total'];
    const rows = [['0.00', '0.00', '0.00', '2,955.25']];
    const result = classifyFinancialBlock(headers, rows);
    expect(result.kind).toBe('payment_breakdown');
    expect(result.isWide).toBe(false);
  });
});

// ── §4: Column width computation ──────────────────────────────────────────────

describe('line item column widths', () => {
  it('returns 8 widths summing close to landscape width for 8-col table', () => {
    const widths = computeLineItemColumnWidths(8, LANDSCAPE_WIDTH_DXA);
    expect(widths).toHaveLength(8);
    const sum = widths.reduce((a, b) => a + b, 0);
    expect(sum).toBeCloseTo(LANDSCAPE_WIDTH_DXA, -2);
    // Description column (index 2) should be the widest
    expect(widths[2]).toBeGreaterThan(widths[0]!);
    expect(widths[2]).toBeGreaterThan(widths[3]!);
    expect(widths[2]).toBeGreaterThan(widths[4]!);
  });

  it('returns 7 widths for 7-col table', () => {
    const widths = computeLineItemColumnWidths(7, LANDSCAPE_WIDTH_DXA);
    expect(widths).toHaveLength(7);
  });

  it('returns equal widths for generic column count', () => {
    const widths = computeLineItemColumnWidths(5, 10000);
    expect(widths).toHaveLength(5);
    expect(widths.every(w => w === 2000)).toBe(true);
  });
});

// ── §5: Sanitised two-page receipt fixture ───────────────────────────────────

/**
 * Sanitised translation of a 2-page financial document.
 * Page 1: metadata + 17 line items (8 columns)
 * Page 2: tax summary + amount in words + totals + payment breakdown + terms
 *
 * Upload order: page 2 first, then page 1.
 * After reorder: page 1 before page 2.
 *
 * All company/customer names are fictional. All numbers are fictional.
 */

