const RECEIPT_PAGE2_MARKDOWN = `## Summary

| Field | Value |
|---|---|
| Invoice number | INV-2026-0001 |
| Page | 2 of 2 |

## VAT Summary

| VAT Code | Tax Base | VAT Amount | Gross Amount |
|---|---|---|---|
| 7% | 2,908.87 | 46.38 | 2,955.25 |

## Amount in Words

| Total amount |
|---|
| Two thousand nine hundred fifty five baht twenty five satang |

## Totals

| Item | Amount |
|---|---|
| Total | 2,955.25 |
| Discount | 0.00 |
| Net Amount | 2,955.25 |

## Payment Breakdown

| Cash | Coupon | Voucher | Total Paid |
|---|---|---|---|
| 2,955.25 | 0.00 | 0.00 | 2,955.25 |

## Terms and Conditions

Goods sold are not returnable after 24 hours. Prices include VAT where applicable.

[Rectangular label: For Customer]
`;

describe('two-page receipt regression', () => {
  it('reorders pages correctly (uploaded page 2 first, then page 1)', () => {
    // Upload order: page2, page1
    const result = reorderPagesByEvidence([RECEIPT_PAGE2_MARKDOWN, RECEIPT_PAGE1_MARKDOWN]);
    expect(result.reordered).toBe(true);
    // After reorder: page1 (1 of 2) comes first
    expect(result.reorderedMarkdowns[0]).toContain('Page | 1 of 2');
    expect(result.reorderedMarkdowns[1]).toContain('Page | 2 of 2');
  });

  it('joined markdown starts with page 1 content after reorder', () => {
    const result = reorderPagesByEvidence([RECEIPT_PAGE2_MARKDOWN, RECEIPT_PAGE1_MARKDOWN]);
    const joined = result.reorderedMarkdowns.join('\n\n');
    // Page 1 content (company header) appears before page 2 content (summary)
    const page1pos = joined.indexOf('Goods and Services');
    const page2pos = joined.indexOf('VAT Summary');
    expect(page1pos).toBeGreaterThan(-1);
    expect(page2pos).toBeGreaterThan(-1);
    expect(page1pos).toBeLessThan(page2pos);
  });

  it('line-item table classified as wide line_items', () => {
    const headers = ['#', 'Article', 'Description', 'Qty', 'Unit', 'Unit Price', 'VAT', 'Total'];
    const rows = Array.from({ length: 17 }, (_, i) => [
      String(i + 1), `ART-${String(i + 1).padStart(3, '0')}`, `Product ${i + 1}`,
      '10', 'kg', '45.00', '7%', '450.00',
    ]);
    const result = classifyFinancialBlock(headers, rows);
    expect(result.kind).toBe('line_items');
    expect(result.isWide).toBe(true);
    expect(result.columnCount).toBe(8);
  });

  it('renders DOCX with 17 line items — all article codes in XML', async () => {
    const joined = [RECEIPT_PAGE1_MARKDOWN, RECEIPT_PAGE2_MARKDOWN].join('\n\n');
    const docxBuf = await renderToDocx(joined, RENDER_META, []);
    const xml = await getDocxXml(docxBuf);
    const text = extractPlainText(xml);

    // All 17 article codes must survive
    for (let i = 1; i <= 17; i++) {
      const code = `ART-${String(i).padStart(3, '0')}`;
      expect(text).toContain(code);
    }
  });

  it('DOCX XML does not contain standalone chunk marker "Страница N/M"', async () => {
    const joined = [RECEIPT_PAGE1_MARKDOWN, RECEIPT_PAGE2_MARKDOWN].join('\n\n');
    const docxBuf = await renderToDocx(joined, RENDER_META, []);
    const xml = await getDocxXml(docxBuf);
    const text = extractPlainText(xml);

    // Pattern: "Страница N/M" as standalone chunk marker
    expect(text).not.toMatch(/Страница\s+\d+\s*\/\s*\d+(?!\s+\w)/);
  });

  it('DOCX XML contains the exact fixture totals values', async () => {
    const joined = [RECEIPT_PAGE1_MARKDOWN, RECEIPT_PAGE2_MARKDOWN].join('\n\n');
    const docxBuf = await renderToDocx(joined, RENDER_META, []);
    const xml = await getDocxXml(docxBuf);
    const text = extractPlainText(xml);

    expect(text).toContain('2,908.87');
    expect(text).toContain('46.38');
    expect(text).toContain('2,955.25');
    expect(text).toContain('0.00');
  });

  it('invoice number preserved in DOCX', async () => {
    const joined = [RECEIPT_PAGE1_MARKDOWN, RECEIPT_PAGE2_MARKDOWN].join('\n\n');
    const docxBuf = await renderToDocx(joined, RENDER_META, []);
    const xml = await getDocxXml(docxBuf);
    expect(xml).toContain('INV-2026-0001');
  });

  it('legal entity not converted to ООО — "Alpha Trading Public Company Limited" preserved', async () => {
    const joined = [RECEIPT_PAGE1_MARKDOWN, RECEIPT_PAGE2_MARKDOWN].join('\n\n');
    const docxBuf = await renderToDocx(joined, RENDER_META, []);
    const xml = await getDocxXml(docxBuf);
    const text = extractPlainText(xml);

    // Should not contain fabricated ООО/ТОО conversion
    expect(text).not.toMatch(/ООО Alpha|ООО CP|ТОО Alpha/);
    // The original name should be present
    expect(text).toContain('Alpha Trading');
  });

  it('DOCX is valid and non-empty', async () => {
    const joined = [RECEIPT_PAGE1_MARKDOWN, RECEIPT_PAGE2_MARKDOWN].join('\n\n');
    const docxBuf = await renderToDocx(joined, RENDER_META, []);
    expect(docxBuf.length).toBeGreaterThan(5000);
  });
});

// ── §6: Summary blocks are separate from line-item grid ──────────────────────

describe('summary blocks separate from line-item grid', () => {
  it('VAT summary classified as tax_summary (not line_items)', () => {
    const headers = ['VAT Code', 'Tax Base', 'VAT Amount', 'Gross Amount'];
    const rows = [['7%', '2,908.87', '46.38', '2,955.25']];
    const result = classifyFinancialBlock(headers, rows);
    expect(result.kind).toBe('tax_summary');
    expect(result.isWide).toBe(false);
  });

  it('2-column totals table classified as totals', () => {
    const headers = ['Item', 'Amount'];
    const rows = [
      ['Total', '2,955.25'],
      ['Discount', '0.00'],
      ['Net Amount', '2,955.25'],
    ];
    const result = classifyFinancialBlock(headers, rows);
    expect(result.kind).toBe('totals');
    expect(result.isWide).toBe(false);
  });

  it('payment breakdown with cash/coupon/voucher classified as payment_breakdown', () => {
    const headers = ['Cash', 'Coupon', 'Voucher', 'Total Paid'];
    const rows = [['2,955.25', '0.00', '0.00', '2,955.25']];
    const result = classifyFinancialBlock(headers, rows);
    expect(result.kind).toBe('payment_breakdown');
  });
});

// ── §7: No document AST calls ─────────────────────────────────────────────────

describe('document AST not used in financial rendering', () => {
  it('renderDocxFromAst is not imported by financial-blocks', () => {
    const src = fs.readFileSync(
      path.resolve(__dirname, '../financial-blocks.ts'),
      'utf-8',
    );
    expect(src).not.toContain('renderDocxFromAst');
    expect(src).not.toContain('renderHtmlFromAst');
    expect(src).not.toContain('translateToAst');
  });

  it('page-order module does not import AST', () => {
    const src = fs.readFileSync(
      path.resolve(__dirname, '../page-order.ts'),
      'utf-8',
    );
    expect(src).not.toContain('ast');
  });
});

